mapper.select:
select distinct account_id
from energy_electric_meter_power_record
where record_time >= #{beginTime}
  and record_time < #{endTime}
  and account_id is not null
  and is_deleted = 0

select record.id as record_id, record.account_id as account_id, record.meter_id as meter_id, record.meter_name as meter_name, record.device_no as device_no, record.record_time as record_time, relation.owner_id as owner_id, relation.owner_type as owner_type, relation.owner_name as owner_name, relation.space_id as space_id, relation.space_name as space_name, relation.electric_account_type as electric_account_type from energy_electric_meter_power_record record left join energy_electric_meter_power_relation relation on relation.record_id = record.id and relation.is_deleted = 0 where record.record_time >= #{query.beginTime} and record.record_time < #{query.endTime} and record.account_id in
#{accountId}
and record.is_deleted = 0 order by record.account_id asc, record.meter_id asc, record.record_time asc, record.id asc

select meter.account_id as account_id, meter.id as meter_id, meter.meter_name as meter_name, meter.device_no as device_no, meter.space_id as space_id, space.name as space_name from energy_electric_meter meter left join sys_space space on space.id = meter.space_id and space.is_deleted = 0 where meter.account_id in
#{accountId}
and meter.is_deleted = 0 order by meter.account_id asc, meter.id asc

